import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Arrays;
import java.util.List;

@Controller
public class LogoutController {

    private static final String DEFAULT_REDIRECT_URL = "/login";
    private static final List<String> ALLOWED_DOMAINS = Arrays.asList(
        "example.com",
        "app.example.com",
        "admin.example.com"
    );

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, 
                      HttpServletResponse response,
                      @RequestParam(value = "next", required = false) String next) throws IOException {
        performLogout(request, response, next);
    }

    @GetMapping("/logout")
    public void logoutGet(HttpServletRequest request, 
                         HttpServletResponse response,
                         @RequestParam(value = "next", required = false) String next) throws IOException {
        performLogout(request, response, next);
    }

    private void performLogout(HttpServletRequest request, 
                              HttpServletResponse response,
                              String next) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        String redirectUrl = validateAndGetRedirectUrl(next, request);
        response.sendRedirect(redirectUrl);
    }

    private String validateAndGetRedirectUrl(String next, HttpServletRequest request) {
        if (next == null || next.trim().isEmpty()) {
            return DEFAULT_REDIRECT_URL;
        }

        try {
            if (next.startsWith("/")) {
                return next;
            }

            URI uri = new URI(next);
            
            if (uri.getScheme() == null || uri.getHost() == null) {
                return DEFAULT_REDIRECT_URL;
            }

            if (!uri.getScheme().equals("http") && !uri.getScheme().equals("https")) {
                return DEFAULT_REDIRECT_URL;
            }

            String host = uri.getHost().toLowerCase();
            
            boolean isAllowed = ALLOWED_DOMAINS.stream()
                .anyMatch(domain -> host.equals(domain) || host.endsWith("." + domain));

            if (isAllowed) {
                return next;
            }

            return DEFAULT_REDIRECT_URL;

        } catch (URISyntaxException e) {
            return DEFAULT_REDIRECT_URL;
        }
    }
}